solution_code:
#include <iostream>
#include <iomanip>

int main() {
    int a{};
    int b{};
    std::cin >> a >> b;

    int sum{a + b};
    std::cout << "Sum: " << sum << "\n";

    int product{a * b};
    std::cout << "Product: " << product << "\n";

    // a * 1.0 promotes a to double; result is already double, so = is safe
    double result = a * 1.0 / b;
    std::cout << "As double: " << std::fixed << std::setprecision(2) << result << "\n";

    return 0;
}

