solution_code:
#include <iostream>

bool isSafeConversion(int value) {
    return value >= -32768 && value <= 32767;
}

int main() {
    int n{};
    std::cin >> n;

    bool safe{isSafeConversion(n)};
    std::cout << "Safe: " << (safe ? "yes" : "no") << "\n";
    return 0;
}
